            compromiseReasons.append("symlink_anomalies")
        }
        
        if compromiseReasons.isEmpty {
            return .trusted
        } else {
            return .compromised(reasons: compromiseReasons)
        }
    }
    
    private static func checkForJailbreakFiles() -> Bool {
