                    }
                }
            }
        }
        return false
    }
    
    private static func checkForDebugger() -> Bool {
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        if result == 0 {
            return (info.kp_proc.p_flag & P_TRACED) != 0
        }
        return false
    }
    
    private static func checkForkCapability() -> Bool {
        // On non-jailbroken iOS, fork() is not allowed and returns -1
        // We use a safe indirect check instead of actually forking
        let handle = dlopen(nil, RTLD_NOW)
        let forkPtr = dlsym(handle, "fork")
        dlclose(handle)
        
        // If we can resolve fork, check if the sandbox would allow it
        // by checking for sandbox escape indicators
        if forkPtr != nil {
            // Additional check: try to access /bin/sh which requires jailbreak
            return FileManager.default.fileExists(atPath: "/bin/sh")
        }
        return false
    }
    
    private static func checkForSymbolicLinkAnomalies() -> Bool {
        let pathsToCheck = [
            "/var/lib/undecimus/apt",
            "/Applications",
            "/Library/Ringtones",
            "/Library/Wallpaper"
        ]
        
        for path in pathsToCheck {
            do {
                let attributes = try FileManager.default.attributesOfItem(atPath: path)
                if let fileType = attributes[.type] as? FileAttributeType,
                   fileType == .typeSymbolicLink {
                    return true
                }
            } catch {
                // Path doesn't exist or can't be accessed
            }
        }
        return false
    }
}

// MARK: - Encryption Service

final class EncryptionService {
    
    enum EncryptionError: Error, LocalizedError {
        case keyGenerationFailed
        case encryptionFailed
        case decryptionFailed
        case keychainError(OSStatus)
        case invalidData
        case integrityCheckFailed
        
        var errorDescription: String? {
            switch self {
            case .keyGenerationFailed: return "Failed to generate encryption key"
            case .encryptionFailed: return "Encryption operation failed"
            case .decryptionFailed: return "Decryption operation failed"
            case .keychainError(let status): return "Keychain error: \(status)"
            case .invalidData: return "Invalid data format"
            case .integrityCheckFailed: return "Data integrity check failed"
            }
        }
    }
    
    private let keychainService = "com.bankingapp.encryption"
    private let masterKeyTag = "com.bankingapp.masterkey"
    
    /// Generates or retrieves the master symmetric key from the Keychain
    func getOrCreateMasterKey() throws -> SymmetricKey {
        // Try to retrieve existing key
        if let existingKeyData = try? retrieveKeyFromKeychain(tag: masterKeyTag) {
            return SymmetricKey(data: existingKeyData)
        }
        
        // Generate new key
        let key = SymmetricKey(size: .bits256)
        let keyData = key.withUnsafeBytes { Data($0) }
        try storeKeyInKeychain(keyData: keyData, tag: masterKeyTag)
        return key
    }
    
    /// Encrypts data using AES-GCM with authenticated encryption
    func encrypt(data: Data, using key: SymmetricKey) throws -> Data {
        do {
            let sealedBox = try AES.GCM.seal(data, using: key)
            guard let combined = sealedBox.combined else {
                throw EncryptionError.encryptionFailed
            }
            return combined
        } catch let error as EncryptionError {
            throw error
        } catch {
            throw EncryptionError.encryptionFailed
        }
    }
    
    /// Decrypts AES-GCM encrypted data with authentication verification
    func decrypt(data: Data, using key: SymmetricKey) throws -> Data {
        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            return try AES.GCM.open(sealedBox, using: key)
        } catch {
            throw EncryptionError.decryptionFailed
        }
    }
    
    /// Computes HMAC-SHA256 for data integrity verification
    func computeHMAC(for data: Data, using key: SymmetricKey) -> Data {
        let authCode = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(authCode)
    }
    
    /// Verifies HMAC for data integrity
    func verifyHMAC(_ mac: Data, for data: Data, using key: SymmetricKey) -> Bool {
        let computedMAC = computeHMAC(for: data, using: key)
        // Constant-time comparison
        return mac == computedMAC
    }
    
    // MARK: - Keychain Operations
    
    private func storeKeyInKeychain(keyData: Data, tag: String) throws {
        // Delete any existing key first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw EncryptionError.keychainError(status)
        }
    }
    
    private func retrieveKeyFromKeychain(tag: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw EncryptionError.keychainError(status)
        }
        
        return data
    }
    
    /// Securely wipes key material from memory
    func secureWipe(_ data: inout Data) {
        data.withUnsafeMutableBytes { buffer in
            if let baseAddress = buffer.baseAddress {
                memset(baseAddress, 0, buffer.count)
            }
        }
    }
}

// MARK: - Transaction Models

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
    case payment
}

enum TransactionStatus: String, Codable {
    case pending
    case completed
    case failed
    case blocked
    case requiresAdditionalVerification
}

struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: String
    let fromAccountId: String
    let toAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String
    
    init(type: TransactionType, amount: Decimal, currency: String = "USD",
         fromAccountId: String, toAccountId: String? = nil, description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.fromAccountId = fromAccountId
        self.toAccountId = toAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        var randomBytes = [UInt8](repeating: 0, count: 8)
        _ = SecRandomCopyBytes(kSecRandomDefault, randomBytes.count, &randomBytes)
        let randomHex = randomBytes.map { String(format: "%02x", $0) }.joined()
        return "TXN-\(timestamp)-\(randomHex.prefix(8).uppercased())"
    }
}

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountType: AccountType
    var balance: Decimal
    let currency: String
    let holderName: String
    let isActive: Bool
    
    enum AccountType: String, Codable {
        case checking
        case savings
        case investment
    }
    
    /// Returns masked account number for display
    var maskedAccountNumber: String {
        guard accountNumber.count > 4 else { return accountNumber }
        let lastFour = String(accountNumber.suffix(4))
        let masked = String(repeating: "•", count: accountNumber.count - 4)
        return masked + lastFour
    }
}

// MARK: - Security Policy Manager

final class SecurityPolicyManager {
    
    enum SecurityLevel {
        case full          // All features available
        case restricted    // Limited features, additional verification required
        case blocked       // No financial operations allowed
    }
    
    private var cachedIntegrityStatus: DeviceIntegrityChecker.IntegrityStatus?
    private var lastCheckTimestamp: Date?
    private let checkInterval: TimeInterval = 300 // Re-check every 5 minutes
    
    /// Determines the security level based on comprehensive device integrity checks.
    /// Uses multiple independent checks — never a single weak local flag.
    func determineSecurityLevel() -> SecurityLevel {
        let status = getDeviceIntegrityStatus()
        
        switch status {
        case .trusted:
            return .full
            
        case .compromised(let reasons):
            // Multiple compromise indicators = blocked
            if reasons.count >= 3 {
                return .blocked
            }
            // Debugger or injection = blocked (active attack)
            if reasons.contains("debugger_attached") || reasons.contains("dylib_injection_detected") {
                return .blocked
            }
            // Fewer indicators = restricted with additional verification
            return .restricted
            
        case .unknown:
            return .restricted
        }
    }
    
    /// Gets device integrity status with caching to avoid excessive checks
    func getDeviceIntegrityStatus() -> DeviceIntegrityChecker.IntegrityStatus {
        if let cached = cachedIntegrityStatus,
           let lastCheck = lastCheckTimestamp,
           Date().timeIntervalSince(lastCheck) < checkInterval {
            return cached
        }
        
        let status = DeviceIntegrityChecker.performComprehensiveIntegrityCheck()
        cachedIntegrityStatus = status
        lastCheckTimestamp = Date()
        return status
    }
    
    /// Forces a fresh integrity check (e.g., before high-value transactions)
    func forceIntegrityRecheck() -> DeviceIntegrityChecker.IntegrityStatus {
        cachedIntegrityStatus = nil
        lastCheckTimestamp = nil
        return getDeviceIntegrityStatus()
    }
    
    /// Checks if a specific transaction amount requires enhanced verification
    func requiresEnhancedVerification(amount: Decimal, securityLevel: SecurityLevel) -> Bool {
        switch securityLevel {
        case .full:
            return amount > 10000 // High-value transactions on trusted devices
        case .restricted:
            return true // All transactions on restricted devices
        case .blocked:
            return true // Should not reach here, but require verification
        }
    }
}

// MARK: - Secure Transaction Processor

final class TransactionProcessor {
    
    enum TransactionError: Error, LocalizedError {
        case insufficientFunds
        case accountNotFound
        case accountInactive
        case transactionBlocked(reason: String)
        case encryptionError(underlying: Error)
        case deviceCompromised(reasons: [String])
        case amountInvalid
        case dailyLimitExceeded
        case additionalVerificationRequired
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds:
                return "Insufficient funds for this transaction"
            case .accountNotFound:
                return "Account not found"
            case .accountInactive:
                return "Account is not active"
            case .transactionBlocked(let reason):
                return "Transaction blocked: \(reason)"
            case .encryptionError:
                return "Security error processing transaction"
            case .deviceCompromised(let reasons):
                return "Transaction blocked for security reasons. Issues detected: \(reasons.count)"
            case .amountInvalid:
                return "Invalid transaction amount"
            case .dailyLimitExceeded:
                return "Daily transaction limit exceeded"
            case .additionalVerificationRequired:
                return "Additional verification is required for this transaction"
            }
        }
    }
    
    private let encryptionService: EncryptionService
    private let securityPolicy: SecurityPolicyManager
    private var accounts: [String: Account] = [:]
    private var transactionLog: [Transaction] = []
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactions", attributes: .concurrent)
    private var dailyTransactionTotals: [String: Decimal] = [:] // accountId -> total
    private let dailyLimit: Decimal = 50000
    
    init(encryptionService: EncryptionService = EncryptionService(),
         securityPolicy: SecurityPolicyManager = SecurityPolicyManager()) {
        self.encryptionService = encryptionService
        self.securityPolicy = securityPolicy
    }
    
    // MARK: - Account Management
    
    func addAccount(_ account: Account) {
        transactionQueue.async(flags: .barrier) { [weak self] in
            self?.accounts[account.id] = account
        }
    }
    
    func getAccount(id: String) -> Account? {
        var account: Account?
        transactionQueue.sync {
            account = accounts[id]
        }
        return account
    }
    
    func getAllAccounts() -> [Account] {
        var result: [Account] = []
        transactionQueue.sync {
            result = Array(accounts.values)
        }
        return result
    }
    
    // MARK: - Transaction Processing
    
    /// Processes a financial transaction with full security checks.
    /// Gates sensitive operations behind device integrity verification.
    func processTransaction(_ transaction: Transaction, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        
        // SECURITY: Force fresh integrity check before processing financial transactions
        let integrityStatus = securityPolicy.forceIntegrityRecheck()
        let securityLevel = securityPolicy.determineSecurityLevel()
        
        // SECURITY: Block transactions entirely on severely compromised devices
        switch securityLevel {
        case .blocked:
            if case .compromised(let reasons) = integrityStatus {
                logSecurityEvent(event: "transaction_blocked_device_compromised",
                                 details: reasons.joined(separator: ", "),
                                 transactionRef: transaction.referenceNumber)
                completion(.failure(.deviceCompromised(reasons: reasons)))
                return
            }
            completion(.failure(.transactionBlocked(reason: "Device integrity check failed")))
            return
            
        case .restricted:
            // On restricted devices, require additional verification for ALL transactions
            if securityPolicy.requiresEnhancedVerification(amount: transaction.amount, securityLevel: securityLevel) {
                logSecurityEvent(event: "transaction_requires_additional_verification",
                                 details: "Device in restricted mode",
                                 transactionRef: transaction.referenceNumber)
                // In a real app, this would trigger step-up authentication (e.g., biometric + server-side OTP)
                completion(.failure(.additionalVerificationRequired))
                return
            }
            
        case .full:
            // Check if high-value transaction needs enhanced verification even on trusted devices
            if securityPolicy.requiresEnhancedVerification(amount: transaction.amount, securityLevel: securityLevel) {
                logSecurityEvent(event: "high_value_transaction_verification",
                                 details: "Amount: \(transaction.amount)",
                                 transactionRef: transaction.referenceNumber)
                // Would trigger step-up auth for high-value transactions
            }
        }
        
        // Validate transaction
        do {
            try validateTransaction(transaction)
        } catch let error as TransactionError {
            completion(.failure(error))
            return
        } catch {
            completion(.failure(.transactionBlocked(reason: error.localizedDescription)))
            return
        }
        
        // Process the transaction atomically
        transactionQueue.async(flags: .barrier) { [weak self] in
            guard let self = self else { return }
            
            var mutableTransaction = transaction
            
            do {
                // Execute the transaction
                try self.executeTransaction(&mutableTransaction)
                
                // Encrypt and store the transaction record
                try self.securelyStoreTransaction(mutableTransaction)
                
                DispatchQueue.main.async {
                    completion(.success(mutableTransaction))
                }
            } catch let error as TransactionError {
                mutableTransaction.status = .failed
                DispatchQueue.main.async {
                    completion(.failure(error))
                }
            } catch {
                mutableTransaction.status = .failed
                DispatchQueue.main.async {
                    completion(.failure(.transactionBlocked(reason: error.localizedDescription)))
                }
            }
        }
    }
    
    // MARK: - Transaction Validation
    
    private func validateTransaction(_ transaction: Transaction) throws {
        // Validate amount
        guard transaction.amount > 0 else {
            throw TransactionError.amountInvalid
        }
        
        // Validate source account exists and is active
        guard let sourceAccount = accounts[transaction.fromAccountId] else {
            throw TransactionError.accountNotFound
        }
        
        guard sourceAccount.isActive else {
            throw TransactionError.accountInactive
        }
        
        // Validate destination account for transfers
        if let toAccountId = transaction.toAccountId, transaction.type == .transfer {
            guard let destAccount = accounts[toAccountId] else {
                throw TransactionError.accountNotFound
            }
            guard destAccount.isActive else {
                throw TransactionError.accountInactive
            }
        }
        
        // Check sufficient funds for withdrawals, transfers, and payments
        switch transaction.type {
        case .withdrawal, .transfer, .payment:
            guard sourceAccount.balance >= transaction.amount else {
                throw TransactionError.insufficientFunds
            }
        case .deposit:
            break
        }
        
        // Check daily limits
        let currentDailyTotal = dailyTransactionTotals[transaction.fromAccountId] ?? 0
        guard currentDailyTotal + transaction.amount <= dailyLimit else {
            throw TransactionError.dailyLimitExceeded
        }
    }
    
    // MARK: - Transaction Execution
    
    private func executeTransaction(_ transaction: inout Transaction) throws {
        switch transaction.type {
        case .deposit:
            guard var account = accounts[transaction.fromAccountId] else {
                throw TransactionError.accountNotFound
            }
            account.balance += transaction.amount
            accounts[account.id] = account
            transaction.status = .completed
            
        case .withdrawal:
            guard var account = accounts[transaction.fromAccountId] else {
                throw TransactionError.accountNotFound
            }
            guard account.balance >= transaction.amount else {
                throw TransactionError.insufficientFunds
            }
            account.balance -= transaction.amount
            accounts[account.id] = account
            transaction.status = .completed
            
        case .transfer:
            guard var sourceAccount = accounts[transaction.fromAccountId],
                  let toAccountId = transaction.toAccountId,
                  var destAccount = accounts[toAccountId] else {
                throw TransactionError.accountNotFound
            }
            guard sourceAccount.balance >= transaction.amount else {
                throw TransactionError.insufficientFunds
            }
            sourceAccount.balance -= transaction.amount
            destAccount.balance += transaction.amount
            accounts[sourceAccount.id] = sourceAccount
            accounts[destAccount.id] = destAccount
            transaction.status = .completed
            
        case .payment:
            guard var account = accounts[transaction.fromAccountId] else {
                throw TransactionError.accountNotFound
            }
            guard account.balance >= transaction.amount else {
                throw TransactionError.insufficientFunds
            }
            account.balance -= transaction.amount
            accounts[account.id] = account
            transaction.status = .completed
        }
        
        // Update daily totals
        let currentTotal = dailyTransactionTotals[transaction.fromAccountId] ?? 0
        dailyTransactionTotals[transaction.fromAccountId] = currentTotal + transaction.amount
    }
    
    // MARK: - Secure Storage
    
    private func securelyStoreTransaction(_ transaction: Transaction) throws {
        do {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            let transactionData = try encoder.encode(transaction)
            
            let key = try encryptionService.getOrCreateMasterKey()
            let encryptedData = try encryptionService.encrypt(data: transactionData, using: key)
            
            // Compute HMAC for integrity verification
            let hmac = encryptionService.computeHMAC(for: encryptedData, using: key)
            
            // Store encrypted transaction with HMAC
            let secureRecord = SecureTransactionRecord(
                encryptedData: encryptedData,
                hmac: hmac,
                timestamp: transaction.timestamp
            )
            
            transactionLog.append(transaction)
            
            // In production, this would be persisted to encrypted local storage or sent to server
            _ = secureRecord
            
        } catch {
            throw TransactionError.encryptionError(underlying: error)
        }
    }
    
    // MARK: - Transaction History
    
    /// Retrieves transaction history with integrity verification
    func getTransactionHistory(for accountId: String) -> [Transaction] {
        var result: [Transaction] = []
        transactionQueue.sync {
            result = transactionLog.filter { $0.fromAccountId == accountId || $0.toAccountId == accountId }
        }
        return result.sorted { $0.timestamp > $1.timestamp }
    }
    
    // MARK: - Security Logging
    
    private func logSecurityEvent(event: String, details: String, transactionRef: String) {
        let logEntry: [String: Any] = [
            "event": event,
            "details": details,
            "transactionRef": transactionRef,
            "timestamp": ISO8601DateFormatter().string(from: Date()),
            "deviceModel": UIDevice.current.model,
            "systemVersion": UIDevice.current.systemVersion
        ]
        // In production, send to server-side security monitoring
        print("[SECURITY] \(logEntry)")
    }
}

