        let securityLevel = securityPolicy.determineSecurityLevel()
        
        switch securityLevel {
        case .blocked:
            isDeviceCompromised = true
            securityWarning = "This device has been identified as potentially compromised. Financial operations are disabled for your security. Please use a different device or contact support."
            
        case .restricted:
            isDeviceCompromised = false
            securityWarning = "Additional security verification may be required for transactions on this device."
            
        case .full:
            isDeviceCompromised = false
            securityWarning = nil
        }
    }
    
    /// Loads account data
    func loadAccounts() {
        isLoading = true
        errorMessage = nil
        
        // In production, this would fetch from a secure API
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            self.accounts = self.transactionProcessor.getAllAccounts()
            self.isLoading = false
        }
    }
    
    /// Initiates a transaction with full security checks
    func initiateTransaction(type: TransactionType, amount: Decimal, fromAccountId: String,
                             toAccountId: String? = nil, description: String) {
        
        // Re-check device security before any transaction
        checkDeviceSecurity()
        
        guard !isDeviceCompromised else {
            errorMessage = "Transactions are blocked on this device for security reasons."
            return
        }
        
        isLoading = true
        errorMessage = nil
        
        let transaction = Transaction(
            type: type,
            amount: amount,
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            description: description
        )
        
        transactionProcessor.processTransaction(transaction) { [weak self] result in
            guard let self = self else { return }
            self.isLoading = false
            
            switch result {
            case .success(let completedTransaction):
                self.transactions.insert(completedTransaction, at: 0)
                self.loadAccounts() // Refresh balances
                
            case .failure(let error):
                self.errorMessage = error.localizedDescription
                
                // If device was found compromised during transaction, update UI
                if case .deviceCompromised = error {
                    self.isDeviceCompromised = true
                    self.checkDeviceSecurity()
                }
            }
        }
    }
    
    /// Loads transaction history for a specific account
    func loadTransactionHistory(for accountId: String) {
        transactions = transactionProcessor.getTransactionHistory(for: accountId)
    }
    
    /// Formats currency amount for display
    func formatCurrency(_ amount: Decimal, currency: String = "USD") -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

