import SwiftUI

struct AccountListView: View {
    @StateObject private var viewModel = AccountBalanceViewModel()
    
    var body: some View {
        NavigationView {
            VStack {
                // Security warning banner
                if let warning = viewModel.securityWarning {
                    SecurityWarningBanner(message: warning, isBlocked: viewModel.isDeviceCompromised)
                }
                
                if viewModel.isLoading {
                    ProgressView("Loading accounts...")
                        .padding()
                } else if viewModel.accounts.isEmpty {
                    VStack(spacing: 16) {
                        Image(systemName: "building.columns")
                            .font(.system(size: 60))
                            .foregroundColor(.gray)
                        Text("No accounts found")
                            .font(.headline)
                            .foregroundColor(.secondary)
                    }
                    .padding()
                } else {
                    List(viewModel.accounts) { account in
                        NavigationLink(destination: AccountDetailView(account: account, viewModel: viewModel)) {
                            AccountRowView(account: account, viewModel: viewModel)
                        }
                    }
                }
                
                if let error = viewModel.errorMessage {
                    Text(error)
                        .foregroundColor(.red)
                        .font(.caption)
                        .padding()
                }
            }
            .navigationTitle("Accounts")
            .onAppear {
                viewModel.loadAccounts()
            }
            .refreshable {
                viewModel.checkDeviceSecurity()
                viewModel.loadAccounts()
            }
        }
    }
}

struct SecurityWarningBanner: View {
    let message: String
