    var body: some View {
        HStack {
            Image(systemName: isBlocked ? "exclamationmark.shield.fill" : "exclamationmark.triangle.fill")
                .foregroundColor(.white)
            Text(message)
                .font(.caption)
                .foregroundColor(.white)
                .multilineTextAlignment(.leading)
        }
        .padding()
        .background(isBlocked ? Color.red : Color.orange)
        .cornerRadius(8)
        .padding(.horizontal)
    }
}

