struct TransactionRowView: View {
    let transaction: Transaction
    let viewModel: AccountBalanceViewModel
    
    var body: some View {
        HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                Text(transaction.timestamp, style: .date)
                    .font(.caption)
                    .foregroundColor(.secondary)
                Text(transaction.referenceNumber)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text(transactionAmountText)
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(amountColor)
                
                StatusBadge(status: transaction.status)
            }
        }
        .padding(.vertical, 4)
    }
    
    private var transactionAmountText: String {
        let prefix = transaction.type == .deposit ? "+" : "-"
        return "\(prefix)\(viewModel.formatCurrency(transaction.amount, currency: transaction.currency))"
    }
    
    private var amountColor: Color {
        transaction.type == .deposit ? .green : .red
    }
}

struct StatusBadge: View {
    let status: TransactionStatus
    
    var body: some View {
        Text(status.rawValue.capitalized)
            .font(.caption2)
            .fontWeight(.medium)
            .foregroundColor(.white)
            .padding(.horizontal, 6)
            .padding(.vertical, 2)
            .background(statusColor)
            .cornerRadius(4)
    }
    
    private var statusColor: Color {
        switch status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .blocked: return .red
        case .requiresAdditionalVerification: return .purple
        }
    }
}

struct TransferView: View {
    let fromAccount: Account
    @ObservedObject var viewModel: AccountBalanceViewModel
    @Environment(\.dismiss) private var dismiss
    
    @State private var amount: String = ""
    @State private var toAccountId: String = ""
    @State private var description: String = ""
    @State private var showingConfirmation = false
    
    var body: some View {
        NavigationView {
            Form {
                Section("From Account") {
                    Text("\(fromAccount.accountType.rawValue.capitalized) - \(fromAccount.maskedAccountNumber)")
                    Text("Balance: \(viewModel.formatCurrency(fromAccount.balance))")
                        .foregroundColor(.secondary)
                }
                
                Section("Transfer Details") {
                    TextField("Amount", text: $amount)
                        .keyboardType(.decimalPad)
                    TextField("To Account ID", text: $toAccountId)
                    TextField("Description", text: $description)
                }
                
                if let error = viewModel.errorMessage {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
                
                Section {
                    Button("Transfer") {
                        showingConfirmation = true
                    }
                    .disabled(amount.isEmpty || toAccountId.isEmpty)
                }
            }
            .navigationTitle("Transfer Funds")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert("Confirm Transfer", isPresented: $showingConfirmation) {
                Button("Cancel", role: .cancel) { }
                Button("Confirm") {
                    executeTransfer()
                }
            } message: {
                Text("Transfer \(amount) to account \(toAccountId)?")
            }
        }
    }
    
    private func executeTransfer() {
        guard let decimalAmount = Decimal(string: amount) else {
            viewModel.errorMessage = "Invalid amount"
            return
        }
        
        viewModel.initiateTransaction(
            type: .transfer,
            amount: decimalAmount,
            fromAccountId: fromAccount.id,
            toAccountId: toAccountId,
            description: description.isEmpty ? "Transfer" : description
        )
    }
}

// MARK: - App Entry Point Demo Setup

final class BankingAppModule {
    
    let transactionProcessor: TransactionProcessor
    let securityPolicy: SecurityPolicyManager
    let encryptionService: EncryptionService
    
    init() {
        self.encryptionService = EncryptionService()
        self.securityPolicy = SecurityPolicyManager()
        self.transactionProcessor = TransactionProcessor(
            encryptionService: encryptionService,
            securityPolicy: securityPolicy
        )
    }
    
    /// Sets up demo accounts for testing
    func setupDemoAccounts() {
        let checking = Account(
            id: "ACC001",
            accountNumber: "1234567890",
            accountType: .checking,
            balance: 5250.75,
            currency: "USD",
            holderName: "John Doe",
            isActive: true
        )
        
        let savings = Account(
            id: "ACC002",
            accountNumber: "0987654321",
            accountType: .savings,
            balance: 15000.00,
            currency: "USD",
            holderName: "John Doe",
            isActive: true
        )
        
        let investment = Account(
            id: "ACC003",
            accountNumber: "5555666677",
            accountType: .investment,
            balance: 42500.50,
            currency: "USD",
            holderName: "John Doe",
            isActive: true
        )
        
        transactionProcessor.addAccount(checking)
        transactionProcessor.addAccount(savings)
        transactionProcessor.addAccount(investment)
    }
    
    /// Performs initial security assessment
    func performSecurityAssessment() -> SecurityPolicyManager.SecurityLevel {
        let level = securityPolicy.determineSecurityLevel()
        
        switch level {
        case .full:
            print("[SECURITY] Device integrity: TRUSTED - All features available")
        case .restricted:
            print("[SECURITY] Device integrity: RESTRICTED - Additional verification required")
        case .blocked:
            print("[SECURITY] Device integrity: BLOCKED - Financial operations disabled")
        }
        
        return level
    }
}